options {
  server = server;
  exit = exit;
}

contract OApp(
  bytes32 oappCtrlAssetId,
  bytes32 oappIDAssetId,
  bytes32 usdt0AssetId,
  bytes32 endpointCtrlAssetId,
  bytes32 endpointIDAssetId,
  bytes32 endpointID,
  bytes32 oappID,
  int     remoteEID,
  bytes32 remoteOApp,
  int     exit
) {

  function receive() {
    require(size(tx.inputs[0].packet(17)) == 219, "lz receive packet size");
    require(substr(tx.inputs[0].packet(17), 0, 1) == 1, "lz receive version");

    require(
      bin2num(substr(tx.inputs[0].packet(17), 141, 4)) == 74,
      "credit message length"
    );

    require(
      tx.inputs[0].assets.lookup(endpointIDAssetId) == 1,
      "marker asset not on input 0"
    );
    let endpointIDGroup = tx.assetGroups.find(endpointIDAssetId);
    require(endpointIDGroup.sumOutputs == 0, "marker not burned");

    require(
      substr(tx.inputs[0].packet(17), 1, 32) == oappID,
      "lz receiver != oappID"
    );
    require(
      bin2num(substr(tx.inputs[0].packet(17), 33, 4)) == remoteEID,
      "lz srcEID != remoteEID"
    );
    require(
      substr(tx.inputs[0].packet(17), 37, 32) == remoteOApp,
      "lz sender != remoteOApp"
    );

    require(
      sha256(substr(tx.inputs[0].packet(17), 145, 74))
        == substr(tx.inputs[0].packet(17), 109, 32),
      "credit message hash mismatch"
    );

    require(
      substr(tx.inputs[0].packet(17), 187, 32) == substr(tx.inputs[0].packet(17), 37, 32),
      "credit remoteSender mismatch"
    );

    require(
      tx.outputs[1].scriptPubKey == substr(tx.inputs[0].packet(17), 147, 32),
      "recipient pkScript mismatch"
    );

    require(
      tx.outputs[1].assets.lookup(usdt0AssetId)
        == bin2num(substr(tx.inputs[0].packet(17), 179, 8)),
      "recipient amount mismatch"
    );

    let usdt0Group = tx.assetGroups.find(usdt0AssetId);
    require(
      usdt0Group.delta == bin2num(substr(tx.inputs[0].packet(17), 179, 8)),
      "usdt0 delta != credit amount"
    );

    require(
      tx.outputs[0].scriptPubKey == new OApp(
        oappCtrlAssetId, oappIDAssetId, usdt0AssetId,
        endpointCtrlAssetId, endpointIDAssetId,
        endpointID, oappID, remoteEID, remoteOApp, exit
      ),
      "oapp state must continue"
    );
    require(tx.outputs[0].assets.lookup(oappCtrlAssetId) == 1, "oapp control missing");
    require(tx.outputs[0].assets.lookup(oappIDAssetId) == 1, "oapp id missing");
  }

  function send(bytes32 sendMarkerScriptHash) {
    require(size(tx.packet(20)) == 175, "send invocation packet size");
    require(substr(tx.packet(20), 0, 1) == 1, "send invocation version");

    require(substr(tx.packet(20), 1, 32) == oappID, "invocation oappID");
    require(substr(tx.packet(20), 33, 32) == endpointID, "invocation endpointID");

    require(bin2num(substr(tx.packet(20), 67, 4)) == remoteEID, "invocation dstEID");
    require(substr(tx.packet(20), 71, 32) == remoteOApp, "invocation receiver");

    require(bin2num(substr(tx.packet(20), 65, 2)) == 1, "invocation_vout != 1");

    let usdt0Group = tx.assetGroups.find(usdt0AssetId);
    require(
      usdt0Group.sumInputs == usdt0Group.sumOutputs + bin2num(substr(tx.packet(20), 103, 8)),
      "burn amount mismatch"
    );

    require(
      tx.outputs[1].assets.lookup(oappIDAssetId) == 1,
      "send marker asset missing"
    );
    require(
      tx.outputs[1].scriptPubKey == new SendMarker(
        sendMarkerScriptHash, endpointCtrlAssetId, exit
      ),
      "send marker pkScript not canonical"
    );
    let oappIDGroup = tx.assetGroups.find(oappIDAssetId);
    require(oappIDGroup.sumOutputs == 1, "extra send marker minted");

    require(
      tx.outputs[0].scriptPubKey == new OApp(
        oappCtrlAssetId, oappIDAssetId, usdt0AssetId,
        endpointCtrlAssetId, endpointIDAssetId,
        endpointID, oappID, remoteEID, remoteOApp, exit
      ),
      "oapp state must continue"
    );
    require(tx.outputs[0].assets.lookup(oappCtrlAssetId) == 1, "oapp control missing");
  }
}
